import{_ as a,o as t,c as r,ai as n}from"./chunks/framework.CCqJdmEn.js";const p=JSON.parse('{"title":"GHGA","description":"","frontmatter":{},"headers":[],"relativePath":"projects/ghga.md","filePath":"projects/ghga.md"}'),o={name:"projects/ghga.md"};function s(i,e,d,h,l,c){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="ghga" tabindex="-1">GHGA <a class="header-anchor" href="#ghga" aria-label="Permalink to &quot;GHGA&quot;">​</a></h1><p>The German Human Genome-Phenome Archive - <a href="https://ghga.de" target="_blank" rel="noreferrer">GHGA</a></p><p><strong>Funding:</strong> DFG (funding number: 441914366)<br><strong>Project runtime:</strong> 01.10.2020 - 31.12.2028</p><p>As a secure national omics data infrastructure, GHGA enables the use of human omics data in research, while ensuring data security and preventing misuse. By bridging the gap between research and healthcare, we drive the development of new therapies and diagnostics.</p><p>To do so, GHGA takes a multilayered approach to data security, building advanced infrastructure and a ethics-legal framework for GDPR-compliant data processing, as well as enabling controlled, yet FAIR data access.</p><p>While being a consortium of the German National Research Data Infrastructure (<a href="https://www.nfdi.de/?lang=en" target="_blank" rel="noreferrer">NFDI</a>), GHGA is also embedded in European activities, such as the federated European Genome-Phenome Archive (<a href="https://ega-archive.org/about/projects-and-funders/federated-ega/" target="_blank" rel="noreferrer">FEGA</a>) and the European Genomic Data Infrastructure (<a href="https://gdi.onemilliongenomes.eu/" target="_blank" rel="noreferrer">GDI</a>).</p><h2 id="ghga-data-portal" tabindex="-1">GHGA Data Portal <a class="header-anchor" href="#ghga-data-portal" aria-label="Permalink to &quot;GHGA Data Portal&quot;">​</a></h2><p>Launched on August, 1 2024, the Archive phase of the <a href="https://data.ghga.de/" target="_blank" rel="noreferrer">GHGA Data Portal</a> allows users to access data stored within GHGA Archive through a fully integrated data access management system. It also implements two-factor authentication via Life Science Login for users.</p><p>The datasets within are annotated following the latest version of the <a href="https://www.ghga.de/resources/metadata-model" target="_blank" rel="noreferrer">GHGA Metadata Model</a>, which is compatible with the metadata model of the EGA.</p><p>The GHGA infrastructure is serviced by a federated network of seven data hubs. These are connected to local centers that are major producers of genomic data which will be integrated into GHGA.</p><h2 id="genomde-model-project" tabindex="-1">genomDE model project <a class="header-anchor" href="#genomde-model-project" aria-label="Permalink to &quot;genomDE model project&quot;">​</a></h2><p>Within the <a href="https://www.bfarm.de/DE/Das-BfArM/Aufgaben/Modellvorhaben-Genomsequenzierung/_verteilerseite.html" target="_blank" rel="noreferrer">genomDE model project</a>, GHGA provides the archiving and research platform for the generated genomic data, supporting the aims for earlier and more precise diagnosis and treatments tailored to the individual genetic profiles of patients.</p>',12)])])}const m=a(o,[["render",s]]);export{p as __pageData,m as default};
